37	library IEEE;
38	use			IEEE.STD_LOGIC_1164.all;
39	use			IEEE.NUMERIC_STD.all;
40	
41	library PoC;
42	use			PoC.utils.all;
43	
44	
45	package components is
46		-- implement an optional register stage
47		function registered(signal Clock : std_logic; constant IsRegistered : boolean) return boolean;
48	
49		-- FlipFlop functions
50		-- ===========================================================================
51		-- RS-FlipFlops
52		function ffrs(q : std_logic;	rst : std_logic := '0'; set : std_logic := '0') return std_logic;				-- RS-FlipFlop with dominant rst
53		function ffsr(q : std_logic;	rst : std_logic := '0'; set : std_logic := '0') return std_logic;				-- RS-FlipFlop with dominant set
54		-- D-FlipFlops (Delay)
55		function ffdre(q : std_logic;					d : std_logic;				rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic := '0')												return std_logic;					-- D-FlipFlop with reset and enable
56		function ffdre(q : std_logic_vector;	d : std_logic_vector;	rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic_vector := (0 to 0 => '0'))	return std_logic_vector;	-- D-FlipFlop with reset and enable
57		function ffdse(q : std_logic;					d : std_logic;				set : std_logic := '0'; en : std_logic := '1')																													return std_logic;					-- D-FlipFlop with set and enable
58		-- T-FlipFlops (Toggle)
59		function fftre(q : std_logic;					t : std_logic;				rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic := '0')												return std_logic;					-- T-FlipFlop with reset and enable
60		function fftse(q : std_logic;					t : std_logic;				set : std_logic := '0'; en : std_logic := '1')																													return std_logic;					-- T-FlipFlop with set and enable
61	
62		-- counter
63		function upcounter_next(cnt : unsigned; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : natural := 0) return unsigned;
64		function upcounter_equal(cnt : unsigned; value : natural) return std_logic;
65		function downcounter_next(cnt : signed; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : integer := 0) return signed;
66		function downcounter_equal(cnt : signed; value : integer) return std_logic;
67		function downcounter_neg(cnt : signed) return std_logic;
68	
69		-- shiftregisters
70		function shreg_left(q : std_logic_vector; i : std_logic; en : std_logic := '1') return std_logic_vector;
71		function shreg_right(q : std_logic_vector; i : std_logic; en : std_logic := '1') return std_logic_vector;
72		-- rotate registers
73		function rreg_left(q : std_logic_vector; en : std_logic := '1') return std_logic_vector;
74		function rreg_right(q : std_logic_vector; en : std_logic := '1') return std_logic_vector;
75	
76		-- compare
77		function comp(value1 : std_logic_vector; value2 : std_logic_vector) return std_logic_vector;
78		function comp(value1 : unsigned; value2 : unsigned) return unsigned;
79		function comp(value1 : signed; value2 : signed) return signed;
80		function comp_allzero(value	: std_logic_vector)	return std_logic;
81		function comp_allzero(value	: unsigned)					return std_logic;
82		function comp_allzero(value	: signed)						return std_logic;
83		function comp_allone(value	: std_logic_vector)	return std_logic;
84		function comp_allone(value	: unsigned)					return std_logic;
85		function comp_allone(value	: signed)						return std_logic;
86	
87		-- multiplexing
88		function mux(sel : std_logic; sl0		: std_logic;				sl1		: std_logic)				return std_logic;
89		function mux(sel : std_logic; slv0	: std_logic_vector;	slv1	: std_logic_vector)	return std_logic_vector;
90		function mux(sel : std_logic; us0		: unsigned;					us1		: unsigned)					return unsigned;
91		function mux(sel : std_logic; s0		: signed;						s1		: signed)						return signed;
92	end package;
93	
94	
95	package body components is
96		-- implement an optional register stage
97		-- ===========================================================================
98		function registered(signal Clock : std_logic; constant IsRegistered : boolean) return boolean is
99		begin
100			return ite(IsRegistered, rising_edge(Clock), TRUE);
101		end function;
102	
103		-- FlipFlops
104		-- ===========================================================================
105		-- D-flipflop with reset and enable
106		function ffdre(q : std_logic; d : std_logic; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic := '0') return std_logic is
107		begin
108			if not SIMULATION then
109				if (INIT = '0') then
110					return ((d and en) or (q and not en)) and not rst;
111				elsif (INIT = '1') then
112					return ((d and en) or (q and not en)) or rst;
113				else
114					report "Unsupported INIT value for synthesis." severity FAILURE;
115					return 'X';
116				end if;
117			elsif (rst = '1') then
118				return INIT;
119			else
120				return ((d and en) or (q and not en));
121			end if;
122		end function;
123	
124		function ffdre(q : std_logic_vector; d : std_logic_vector; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic_vector := (0 to 0 => '0')) return std_logic_vector is
125			constant INIT_I		: std_logic_vector(q'range)		:= resize(INIT, q'length);
126			variable Result		: std_logic_vector(q'range);
127		begin
128			for i in q'range loop
129				Result(i)		:= ffdre(q => q(i), d => d(i), rst => rst, en => en, INIT => INIT_I(i));
130			end loop;
131			return Result;
132		end function;
133	
134		-- D-flipflop with set and enable
135		function ffdse(q : std_logic; d : std_logic; set : std_logic := '0'; en : std_logic := '1') return std_logic is
136		begin
137			return ffdre(q => q, d => d, rst => set, en => en, INIT => '1');
138		end function;
139	
140		-- T-flipflop with reset and enable
141		function fftre(q : std_logic; t : std_logic; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : std_logic := '0') return std_logic is
142		begin
143			if not SIMULATION then
144				if (INIT = '0') then
145					return ((not q and (t and en)) or (q and not (t and en))) and not rst;
146				elsif (INIT = '1') then
147					return ((not q and (t and en)) or (q and not (t and en))) or rst;
148				else
149					report "Unsupported INIT value for synthesis." severity FAILURE;
150					return 'X';
151				end if;
152			elsif (rst = '1') then
153				return INIT;
154			else
155				return ((not q and (t and en)) or (q and not (t and en)));
156			end if;
157		end function;
158	
159		-- T-flipflop with set and enable
160		function fftse(q : std_logic; t : std_logic; set : std_logic := '0'; en : std_logic := '1') return std_logic is
161		begin
162			return fftre(q => q, t => t, rst => set, en => en, INIT => '1');
163		end function;
164	
165		-- RS-flipflop with dominant rst
166		function ffrs(q : std_logic; rst : std_logic := '0'; set : std_logic := '0') return std_logic is
167		begin
168			return (q or set) and not rst;
169		end function;
170	
171		-- RS-flipflop with dominant set
172		function ffsr(q : std_logic; rst : std_logic := '0'; set : std_logic := '0') return std_logic is
173		begin
174			return (q and not rst) or set;
175		end function;
176	
177	
178		-- Counters
179		-- ===========================================================================
180		-- up-counter
181		function upcounter_next(cnt : unsigned; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : natural := 0) return unsigned is
182		begin
183			if (rst = '1') then
184				return to_unsigned(INIT, cnt'length);
185			elsif (en = '1') then
186				return cnt + 1;
187			else
188				return cnt;
189			end if;
190		end function;
191	
192		function upcounter_equal(cnt : unsigned; value : natural) return std_logic is
193		begin
194			-- optimized comparison for only up counting values
195			return to_sl((cnt and to_unsigned(value, cnt'length)) = value);
196		end function;
197	
198		-- down-counter
199		function downcounter_next(cnt : signed; rst : std_logic := '0'; en : std_logic := '1'; constant INIT : integer := 0) return signed is
200		begin
201			if (rst = '1') then
202				return to_signed(INIT, cnt'length);
203			elsif (en = '1') then
204				return cnt - 1;
205			else
206				return cnt;
207			end if;
208		end function;
209	
210		function downcounter_equal(cnt : signed; value : integer) return std_logic is
211		begin
212			-- optimized comparison for only down counting values
213			return to_sl((cnt nor to_signed(value, cnt'length)) /= value);
214		end function;
215	
216		function downcounter_neg(cnt : signed) return std_logic is
217		begin
218			return cnt(cnt'high);
219		end function;
220	
221		-- Shift/Rotate Registers
222		-- ===========================================================================
223		function shreg_left(q : std_logic_vector; i : std_logic; en : std_logic := '1') return std_logic_vector is
224		begin
225			return mux(en, q, q(q'left - 1 downto q'right) & i);
226		end function;
227	
228		function shreg_right(q : std_logic_vector; i : std_logic; en : std_logic := '1') return std_logic_vector is
229		begin
230			return mux(en, q, i & q(q'left downto q'right - 1));
231		end function;
232	
233		function rreg_left(q : std_logic_vector; en : std_logic := '1') return std_logic_vector is
234		begin
235			return mux(en, q, q(q'left - 1 downto q'right) & q(q'left));
236		end function;
237	
238		function rreg_right(q : std_logic_vector; en : std_logic := '1') return std_logic_vector is
239		begin
240			return mux(en, q, q(q'right) & q(q'left downto q'right - 1));
241		end function;
242	
243		-- compare functions
244		-- ===========================================================================
245		-- Returns, when
246		--	1-		=> value1 < value2 (difference is negative)
247		--	00		=> value1 = value2 (difference is zero)
248		--	-1		=> value1 > value2 (difference is positive)
249		function comp(value1 : std_logic_vector; value2 : std_logic_vector) return std_logic_vector is
250		begin
251			report "Comparing two STD_LOGIC_VECTORs - implicit conversion to UNSIGNED" severity WARNING;
252			return std_logic_vector(comp(unsigned(value1), unsigned(value2)));
253		end function;
254	
255		function comp(value1 : unsigned; value2 : unsigned) return unsigned is
256		begin
257			if value1 < value2 then
258				return "10";
259			elsif value1 = value2 then
260				return "00";
261			else
262				return "01";
263			end if;
264		end function;
265	
266		function comp(value1 : signed; value2 : signed) return signed is
267		begin
268			if value1 < value2 then
269				return "10";
270			elsif value1 = value2 then
271				return "00";
272			else
273				return "01";
274			end if;
275		end function;
276	
277		function comp_allzero(value	: std_logic_vector) return std_logic is
278		begin
279			return comp_allzero(unsigned(value));
280		end function;
281	
282		function comp_allzero(value	: unsigned) return std_logic is
283		begin
284			return to_sl(value = (value'range => '0'));
285		end function;
286	
287		function comp_allzero(value	: signed) return std_logic is
288		begin
289			return to_sl(value = (value'range => '0'));
290		end function;
291	
292		function comp_allone(value	: std_logic_vector) return std_logic is
293		begin
294			return comp_allone(unsigned(value));
295		end function;
296	
297		function comp_allone(value	: unsigned) return std_logic is
298		begin
299			return to_sl(value = (value'range => '1'));
300		end function;
301	
302		function comp_allone(value	: signed) return std_logic is
303		begin
304			return to_sl(value = (value'range => '1'));
305		end function;
306	
307	
308		-- multiplexers
309		function mux(sel : std_logic; sl0 : std_logic; sl1 : std_logic) return std_logic is
310		begin
311			return (sl0 and not sel) or (sl1 and sel);
312		end function;
313	
314		function mux(sel : std_logic; slv0 : std_logic_vector; slv1 : std_logic_vector) return std_logic_vector is
315		begin
316			return (slv0 and not (slv0'range => sel)) or (slv1 and (slv1'range => sel));
317		end function;
318	
319		function mux(sel : std_logic; us0 : unsigned; us1 : unsigned) return unsigned is
320		begin
321			return (us0 and not (us0'range => sel)) or (us1 and (us1'range => sel));
322		end function;
323	
324		function mux(sel : std_logic; s0 : signed; s1 : signed) return signed is
325		begin
326			return (s0 and not (s0'range => sel)) or (s1 and (s1'range => sel));
327		end function;
328	end package body;
